import{_ as t,o as a,c as i,a3 as o}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"9. Nature Of Relationship","description":"","frontmatter":{"title":"9. Nature Of Relationship","eba":"Doctors in Training 2022-2026","topics":["employment","preliminary"]},"headers":[],"relativePath":"ebas/doctors-in-training/preliminary/9-nature-of-relationship.md","filePath":"ebas/doctors-in-training/preliminary/9-nature-of-relationship.md"}'),r={name:"ebas/doctors-in-training/preliminary/9-nature-of-relationship.md"};function n(s,e,l,p,c,h){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="_9-nature-of-relationship" tabindex="-1">9. Nature Of Relationship <a class="header-anchor" href="#_9-nature-of-relationship" aria-label="Permalink to &quot;9. Nature Of Relationship&quot;">​</a></h1><p><strong>9.1</strong> All minimum entitlements available to the Doctor arise through this Agreement and the NES. In most cases, the employment contract will only prescribe and enforce the time period for the employment relationship, whether the employment is full time or part time or casual and require the Doctor to abide by Health Service policies and procedures.</p><p><strong>9.2</strong> A Rotation Hospital must apply the Parent Hospital employment contract (refer to Definitions (subclauses 3.1(aa), 3.1(cc) and 3.1(ee)) and <a href="/eba/ebas/doctors-in-training/doctor-employment/24-rotations-between-hospitals.html">clause 24</a>).</p><p><strong>9.3</strong> Doctors participating in accredited Specialist training are generally required to maintain two discrete relationships: a trainee relationship with a Specialist Medical College and an employment relationship with a Health Service.</p><p><strong>9.4</strong> Where a Doctor takes up a Specialist training position accredited by the Specialist Medical College, it is the Health Service that employs the Doctor into the allocated position.</p><p>WORKING ARRANGEMENTS</p><p>Plain language terms: employment relationship.</p>',7)])])}const u=t(r,[["render",n]]);export{d as __pageData,u as default};
